SELECT "Credit Memo" AS DocType, [Sales Cr_Memo Line].Type, [Sales Cr_Memo Header].No_, [Sales Cr_Memo Header].[VAT Registration No_], [Sales Cr_Memo Header].[Bill-to Name], [Sales Cr_Memo Header].[Bill-to Country_Region Code], Item.[Country_Region of Origin Code], [Sales Cr_Memo Header].[Ship-to Country_Region Code], Item.[Tariff No_], -Val([item.Gross Weight])*Val([no_ of pairs]) AS PesoLordo, -Val([no_ of pairs]) AS Unita, Item.Description, -Val([Amount]) AS ImportoNetto, -(Val([Amount])+Val([inv_ discount amount])+Val([Line discount amount])) AS ImportoLordo, Item.[Trademark Code] AS Marchio, Vendor.Name AS Fornitore, [Sales Cr_Memo Header].[Posting Date] AS DataRegistrazione, IIf([Sales Cr_Memo Line.Gen_ Bus_ Posting Group]="NAZIONALE","ITALIA","ESTERO") AS Paese, [Sales Cr_Memo Header].[Currency Code] AS Valuta
FROM ([Sales Cr_Memo Line] INNER JOIN [Sales Cr_Memo Header] ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_) INNER JOIN (Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON [Sales Cr_Memo Line].No_ = Item.No_
WHERE ((([Sales Cr_Memo Line].Type)=19 Or ([Sales Cr_Memo Line].Type)=20) AND (([Sales Cr_Memo Header].[Posting Date]) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]) AND ((Item.[advertising material])=0));

